CREATE TABLE IF NOT EXISTS heroes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE,
    primary_role TEXT NOT NULL,
    secondary_role TEXT,
    tier TEXT NOT NULL,
    story TEXT,
    skill_p TEXT,
    skill_1 TEXT,
    skill_2 TEXT,
    skill_3 TEXT,
    items TEXT,
    image_url TEXT,
    skins TEXT,
    skill_p_img TEXT,
    skill_1_img TEXT,
    skill_2_img TEXT,
    skill_3_img TEXT,
    win_rate TEXT,
    pick_rate TEXT,
    ban_rate TEXT,
    counters TEXT
);

-- Xóa dữ liệu cũ nếu chạy lại file này
DELETE FROM heroes;

